  ('disabled-57f41407-moex-00230', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於迴避制度之敘述，下列何者正確？', '["以法官為本案之被害人為由，聲請迴避者應於當事人未就該案件有所聲 明或陳述前為之", "聲請法官迴避經裁定駁回者，不得提起抗告", "被聲請迴避之法官，認為該聲請為有理由者，毋庸裁定，即應迴避", "迴避制度的法理基礎為罪疑唯輕原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
