  ('disabled-57f41407-moex-00232', 'disabled-57f41407', 'disabled-57f41407-moex-113-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於刑事程序第三審之敘述，下列何者正確？', '["上訴於第三審法院，非以判決違背法令或事實認定重大違誤為理由，不 得為之", "上訴書狀應敘述上訴之理由；其未敘述者，得於提起上訴後 20 日內補 提理由書於原審法院；未補提者，毋庸命其補提", "第三審法院之判決，應經言詞辯論為之。但法院認為不必要者，得不經 言詞辯論為之", "第三審法院認為上訴不合法或無理由者，應以裁定駁回之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "391f7c61502f", "answer_pdf_sha1": "032ff59ad495", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
